#include <phymod/phymod_definitions.h>
/*set\get PRBS configuration*/
int barchetta2_phy_prbs_config_set(const plp_barchetta_phymod_phy_access_t* phy, uint32_t flags , const plp_barchetta_phymod_prbs_t* prbs);
int barchetta2_phy_prbs_config_get(const plp_barchetta_phymod_phy_access_t* phy, uint32_t flags , plp_barchetta_phymod_prbs_t* prbs);

/*Set\get PRBS enable state*/
